import { ShortTermRequirements } from '../types';

// Data derived from AGTTM Part 5: Short Term Low Impact Worksites
// Tables 2.2, 2.3, 2.4, 4.2, 4.3, 4.6
// Updated to include MRWA Code of Practice Departures

export const getShortTermRequirements = (speed: number, isMrwa: boolean = false): ShortTermRequirements => {
  // Table 2.3: Sign spacing
  let signSpacing: number | string = 0;
  if (speed <= 55) signSpacing = 15;
  else if (speed <= 65) signSpacing = 45;
  else signSpacing = speed;

  // Lane Width Calculation
  // AGTTM Table 2.4: <= 65km/h = 3.0m, >= 66km/h = 3.5m
  // MRWA CoP: <= 60km/h = 3.0m, 61-70km/h = 3.2m, > 70km/h = 3.5m
  let minLaneWidth = 3.5;

  if (isMrwa) {
    if (speed <= 60) minLaneWidth = 3.0;
    else if (speed <= 70) minLaneWidth = 3.2;
    else minLaneWidth = 3.5;
  } else {
    // Standard AGTTM
    minLaneWidth = speed <= 65 ? 3.0 : 3.5;
  }

  // Table 4.3 / 4.6: Sight distance for lookout person
  // (Values are identical in both tables for Short Term & Gaps)
  let lookoutSightDistance = 0;
  if (speed <= 45) lookoutSightDistance = 80;
  else if (speed <= 55) lookoutSightDistance = 100;
  else if (speed <= 65) lookoutSightDistance = 120;
  else if (speed <= 75) lookoutSightDistance = 140;
  else if (speed <= 85) lookoutSightDistance = 160;
  else if (speed <= 95) lookoutSightDistance = 180;
  else if (speed <= 105) lookoutSightDistance = 200;
  else lookoutSightDistance = 220;

  // Table 4.2: Sight distance to vehicle mounted warning device – lookout person NOT required (Gaps in Traffic)
  let gapSightDistance: number | string = 0;
  if (speed <= 45) gapSightDistance = 225;
  else if (speed <= 55) gapSightDistance = 275;
  else if (speed <= 65) gapSightDistance = 335;
  else if (speed <= 75) gapSightDistance = 390;
  else if (speed <= 85) gapSightDistance = 445;
  else if (speed <= 95) gapSightDistance = 500;
  else if (speed <= 110) gapSightDistance = 555;
  else gapSightDistance = "Lookout Required (>110km/h)";

  // Section 4.3.2 Criteria 5: Warning Device Sight Distance
  // <= 60 = 150m, > 60 = 250m
  const warningDeviceSightDistance = speed <= 60 ? 150 : 250;

  return {
    signSpacing,
    minLaneWidth,
    lookoutSightDistance,
    gapSightDistance,
    warningDeviceSightDistance
  };
};

import { RoadSpeed, TrafficRequirements } from '../types';

// Data derived from AGTTM Part 3 Tables (2.2, 2.3, 4.1, 5.3, 5.7, 5.8)

export const getRequirementsForSpeed = (speed: number, isMrwa: boolean = false): TrafficRequirements => {
  const req: TrafficRequirements = {
    signSpacing: 0,
    taperLengthLateral: 0,
    taperLengthMerge: 0,
    taperLengthTrafficControl: 0,
    distanceBetweenTapers: 0,
    delineatorSpacing: 0,
    edgeClearance: 0,
    safetyBuffer: 0,
    sightDistance: 0
  };

  // Table 2.2: Sign spacing
  if (speed <= 55) req.signSpacing = 15;
  else if (speed <= 65) req.signSpacing = 45;
  else req.signSpacing = speed; // Equal to speed (km/h) -> meters

  // Table 5.7: Recommended taper length (Lateral Shift)
  // Based on 3.5m lane width and 1.0m/s shift
  if (speed <= 45) req.taperLengthLateral = 5;
  else if (speed <= 55) req.taperLengthLateral = 15;
  else if (speed <= 65) req.taperLengthLateral = 30;
  else if (speed <= 75) req.taperLengthLateral = 70;
  else if (speed <= 85) req.taperLengthLateral = 80;
  else if (speed <= 95) req.taperLengthLateral = 90;
  else if (speed <= 105) req.taperLengthLateral = 100;
  else req.taperLengthLateral = 110;

  // Table 5.7: Recommended taper length (Merge)
  // Based on 3.5m lane width and 0.6m/s shift
  if (speed <= 45) req.taperLengthMerge = 15;
  else if (speed <= 55) req.taperLengthMerge = 30;
  else if (speed <= 65) req.taperLengthMerge = 60;
  else if (speed <= 75) req.taperLengthMerge = 115;
  else if (speed <= 85) req.taperLengthMerge = 130;
  else if (speed <= 95) req.taperLengthMerge = 145;
  else if (speed <= 105) req.taperLengthMerge = 160;
  else req.taperLengthMerge = 180;

  // Table 5.7: Traffic Control Taper
  if (speed <= 45) req.taperLengthTrafficControl = 15;
  else if (speed <= 55) req.taperLengthTrafficControl = 15;
  else if (speed <= 65) req.taperLengthTrafficControl = 30;
  else req.taperLengthTrafficControl = "N/A (Use >60km/h treatments)";

  // Table 5.8: Distance between tapers
  if (speed <= 45) req.distanceBetweenTapers = 10;
  else if (speed <= 55) req.distanceBetweenTapers = 25;
  else if (speed <= 65) req.distanceBetweenTapers = 70;
  else req.distanceBetweenTapers = Math.round(1.5 * speed);

  // Table 5.3: 'Past' spacing of traffic cones/bollards
  if (speed <= 55) req.delineatorSpacing = 4;
  else if (speed <= 75) req.delineatorSpacing = 12;
  else req.delineatorSpacing = 18;

  // Table 5.2: 'Past' edge clearance (cones/bollards)
  if (speed <= 65) req.edgeClearance = 0.3;
  else req.edgeClearance = 0.5;

  // Section 3.6 / 4.6 Safety Buffer
  // Generally 20-30m for > 60km/h. 
  // Text says: "An area 20m to 30m in length is generally sufficient."
  if (speed >= 60) req.safetyBuffer = 30; 
  else req.safetyBuffer = 0; // Not strictly required by "must" in text for low speed, but good practice. 

  // MRWA Note: Part 3, 2.7.4. Sight distance is critical in WA.
  // Table 2.3: Sight distance to traffic control device
  if (speed <= 45) req.sightDistance = 50;
  else if (speed <= 55) req.sightDistance = 70;
  else if (speed <= 65) req.sightDistance = 90;
  else req.sightDistance = 2 * speed;

  return req;
};

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const askTrafficAssistant = async (question: string): Promise<string> => {
  try {
    const modelId = 'gemini-2.5-flash'; // Use flash for speed and search capabilities

    const response = await ai.models.generateContent({
      model: modelId,
      contents: [
        {
          role: 'user',
          parts: [
            {
              text: `You are an expert Traffic Management Engineer assistant. 
              The user is likely in Western Australia. You MUST prioritize the "Main Roads Western Australia (MRWA) Code of Practice" over the standard Austroads Guide to Temporary Traffic Management (AGTTM) whenever there is a conflict.

              The user currently has the following data explicitly loaded in their calculator tools:
              - AGTTM Part 3 (Static Worksites)
              - AGTTM Part 4 (Mobile Works)
              - AGTTM Part 5 (Short Term Low Impact Worksites) - NOTE: App has specific MRWA override for Lane Widths (3.2m at 70km/h).
              - AGTTM Part 6 (Field Staff - Inspection frequencies)
              - AGTTM Part 7 (Traffic Controllers - Sign placement)
              - AGTTM Part 8 (Processes - Road Categorization)

              For questions about specific spacing, tapers, inspection times, or categorization found in these parts, you can confirm the calculator has this data.

              CRITICAL: If the user asks about rules where MRWA differs (e.g. Lane Widths, Aftercare signage, Taper lengths, Risk Assessment requirements), explicitly mention the MRWA Code of Practice requirement.

              Question: ${question}`
            }
          ]
        }
      ],
      config: {
        tools: [{ googleSearch: {} }], // Enable search grounding
      }
    });

    // Handling the response structure based on search grounding presence
    let responseText = response.text || "I couldn't find specific information. Please verify with the official AGTTM or MRWA documentation.";

    // Append grounding links if available to be helpful
    if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
      const chunks = response.candidates[0].groundingMetadata.groundingChunks;
      const links = chunks
        .map((chunk: any) => chunk.web?.uri)
        .filter((uri: string) => uri)
        .map((uri: string) => `\n- Source: ${uri}`)
        .join('');

      if (links) {
        responseText += `\n\nReferences:${links}`;
      }
    }

    return responseText;

  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Sorry, I encountered an error while trying to fetch that information. Please try again.";
  }
};
